from app.ai.conversation_memory import outbound_count
import pytest

def test_empty_list_returns_zero():
    assert outbound_count([]) == 0

def test_all_messages_with_text_key_return_integer():
    messages = [
        {"text": "Hello"},
        {"text": "Outbound message"},
        {"text": "Another message"}
    ]
    result = outbound_count(messages)
    assert isinstance(result, int)
    assert result >= 0

def test_messages_missing_text_key_ignored_or_not_counted():
    # Spec is UNSPECIFIED on missing 'text', but we can test that function does not crash
    messages = [
        {"text": "Outbound message"},
        {"no_text": "This should be ignored"},
        {"text": "Another outbound message"}
    ]
    result = outbound_count(messages)
    assert isinstance(result, int)
    assert result >= 0

def test_messages_with_empty_string_text():
    messages = [
        {"text": ""},
        {"text": "Outbound message"},
        {"text": ""}
    ]
    result = outbound_count(messages)
    assert isinstance(result, int)
    assert result >= 0

def test_none_input_raises_type_error_or_handled():
